 1	import React, { FC, MouseEvent, useMemo, useState } from 'react';
 2	import produce from 'immer';
 3	
 4	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 5	import {
 6	  bootloaderOptions,
 7	  BootModeTitles,
 8	} from '@kubevirt-utils/components/FirmwareBootloaderModal/utils/constants';
 9	import { BootloaderOptionValue } from '@kubevirt-utils/components/FirmwareBootloaderModal/utils/types';
10	import {
11	  getBootloaderFromVM,
12	  updatedVMBootMode,
13	} from '@kubevirt-utils/components/FirmwareBootloaderModal/utils/utils';
14	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
15	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
16	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
17	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
18	import { Form, FormGroup, SelectOption } from '@patternfly/react-core';
19	
20	type TemplateBootloaderModalProps = {
21	  isOpen: boolean;
22	  onClose: () => void;
23	  onSubmit: (updatedVM: V1Template) => Promise<V1Template | void>;
24	  template: V1Template;
25	};
26	
27	const TemplateBootloaderModal: FC<TemplateBootloaderModalProps> = ({
28	  isOpen,
29	  onClose,
30	  onSubmit,
31	  template,
32	}) => {
33	  const { t } = useKubevirtTranslation();
34	  const [selectedFirmwareBootloader, setSelectedFirmwareBootloader] =
35	    useState<BootloaderOptionValue>(getBootloaderFromVM(getTemplateVirtualMachineObject(template)));
36	
37	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: BootloaderOptionValue) => {
38	    event.preventDefault();
39	    setSelectedFirmwareBootloader(value);
40	  };
41	
42	  const updatedTemplate = useMemo(() => {
43	    return produce<V1Template>(template, (templateDraft: V1Template) => {
44	      const vmDraft = getTemplateVirtualMachineObject(templateDraft);
45	      const updatedVM = updatedVMBootMode(vmDraft, selectedFirmwareBootloader);
46	
47	      vmDraft.spec.template.spec.domain = updatedVM.spec.template.spec.domain;
48	    });
49	  }, [selectedFirmwareBootloader, template]);
50	
51	  return (
52	    <TabModal
53	      headerText={t('Boot mode')}
54	      isOpen={isOpen}
55	      obj={updatedTemplate}
56	      onClose={onClose}
57	      onSubmit={onSubmit}
58	    >
59	      <Form>
60	        <FormGroup fieldId="template-firmware-bootloader" label={t('Boot mode')}>
61	          <FormPFSelect
62	            onSelect={handleChange}
63	            selected={selectedFirmwareBootloader}
64	            selectedLabel={BootModeTitles[selectedFirmwareBootloader]}
65	            toggleProps={{ isFullWidth: true }}
66	          >
67	            {bootloaderOptions.map(({ description, title, value }) => (
68	              <SelectOption description={description} key={value} value={value}>
69	                {title}
70	              </SelectOption>
71	            ))}
72	          </FormPFSelect>
73	        </FormGroup>
74	      </Form>
75	    </TabModal>
76	  );
77	};
78	
79	export default TemplateBootloaderModal;

